SELECT id, type, value, description, status, create_time as createTime, update_time as updateTime, create_user_id as createUserId
FROM whitelist
WHERE is_del = 0

    AND (value LIKE CONCAT('%', #{keyword}, '%'))


    AND type = #{type}


    AND status = #{status}

ORDER BY id DESC

    LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM whitelist
WHERE is_del = 0

    AND (value LIKE CONCAT('%', #{keyword}, '%'))


    AND type = #{type}


    AND status = #{status}

SELECT id, whitelist_id as whitelistId, access_ip as accessIp, access_url as accessUrl,
       request_method as requestMethod, access_result as accessResult, fail_reason as failReason,
       user_id as userId, user_agent as userAgent, request_params as requestParams,
       response_code as responseCode, response_time as responseTime, access_time as accessTime
FROM whitelist_access_log
WHERE 1=1

    AND access_ip LIKE CONCAT('%', #{accessIp}, '%')


    AND access_url LIKE CONCAT('%', #{accessUrl}, '%')


    AND access_result = #{accessResult}


    AND access_time >= #{startTime}


    AND access_time <= #{endTime}

ORDER BY access_time DESC

    LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM whitelist_access_log
WHERE 1=1

    AND access_ip LIKE CONCAT('%', #{accessIp}, '%')


    AND access_url LIKE CONCAT('%', #{accessUrl}, '%')


    AND access_result = #{accessResult}


    AND access_time >= #{startTime}


    AND access_time <= #{endTime}

