mapper.select:
SELECT id, whitelist_id as whitelistId, access_ip as accessIp, access_url as accessUrl, request_method as requestMethod, access_result as accessResult, fail_reason as failReason, user_id as userId, user_agent as userAgent, request_params as requestParams, response_code as responseCode, response_time as responseTime, access_time as accessTime FROM whitelist_access_log WHERE 1=1
AND access_ip LIKE CONCAT('%', #{accessIp}, '%')
AND access_url LIKE CONCAT('%', #{accessUrl}, '%')
AND access_result = #{accessResult}
AND access_time >= #{startTime}
AND access_time <= #{endTime}
ORDER BY access_time DESC LIMIT 10000

SELECT COUNT(*) as totalCount, COUNT(DISTINCT access_ip) as uniqueIpCount, COUNT(DISTINCT access_url) as uniqueUrlCount, SUM(CASE WHEN access_result = 'SUCCESS' THEN 1 ELSE 0 END) as successCount, SUM(CASE WHEN access_result = 'DENIED' THEN 1 ELSE 0 END) as deniedCount, SUM(CASE WHEN access_result = 'ERROR' THEN 1 ELSE 0 END) as errorCount, AVG(response_time) as avgResponseTime, MAX(response_time) as maxResponseTime, MIN(response_time) as minResponseTime FROM whitelist_access_log WHERE 1=1
AND access_time >= #{startTime}
AND access_time <= #{endTime}
